module multi_pipe_8bit(
    input clk,
    input rst_n,
    input mul_en_in,
    input [7:0] mul_a,
    input [7:0] mul_b,
    output mul_en_out,
    output [15:0] mul_out
);
// TODO: implement your design here
// Hint: follow the structure of XML, and the document.
// Step1: prepare logic elements (reg/wire)
reg mul_en_out_reg [3:0];
reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] sum [7:0];
reg [15:0] mul_out_reg;
wire [15:0] temp [7:0];
wire [7:0] and_out;
wire [7:0] or_out;
wire [7:0] xor_out;
// Step2: describe partial product generation
genvar i;
generate
    for (i = 0; i < 8; i = i + 1) begin : partial_product_gen
        assign and_out[i] = mul_b_reg[i] & mul_a_reg[0];
        assign or_out[i] = mul_b_reg[i] | mul_a_reg[0];
        assign xor_out[i] = mul_b_reg[i] ^ mul_a_reg[0];
        assign temp[i] = {15'b0, and_out[i]} + {14'b0, or_out[i]} + {13'b0, xor_out[i], 1'b0};
    end
endgenerate
// Step3: describe partial sum calculation
always @(posedge clk) begin
    if (!rst_n) begin
        sum[0] <= 16'b0;
    end
    else begin
        sum[0] <= temp[0];
    end
end
genvar j;
generate
    for (j = 1; j < 8; j = j + 1) begin : partial_sum_calculation
        always @(posedge clk) begin
            if (!rst_n) begin
                sum[j] <= 16'b0;
            end
            else begin
                sum[j] <= sum[j-1] + temp[j];
            end
        end
    end
endgenerate
// Step4: describe final product calculation
always @(posedge clk) begin
    if (!rst_n) begin
        mul_out_reg <= 16'b0;
    end
    else begin
        mul_out_reg <= sum[7];
    end
end
// Step5: describe output assignment
assign mul_en_out = mul_en_out_reg[3];
assign mul_out = mul_en_out ? mul_out_reg : 16'b0;
endmodule
